import{_ as e,a as t,b as n,c as i}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as d,o as s,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Tambah S3 Channel","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/upload/s3.md","filePath":"ms-MY/upload/s3.md","lastUpdated":1781962217000}'),r={name:"ms-MY/upload/s3.md"};function c(u,a,p,k,h,m){return s(),l("div",null,[...a[0]||(a[0]=[o(`<h1 id="tambah-s3-channel" tabindex="-1">Tambah S3 Channel <a class="header-anchor" href="#tambah-s3-channel" aria-label="Permalink to &quot;Tambah S3 Channel&quot;">​</a></h1><h2 id="paling-sesuai-untuk" tabindex="-1">Paling Sesuai Untuk <a class="header-anchor" href="#paling-sesuai-untuk" aria-label="Permalink to &quot;Paling Sesuai Untuk&quot;">​</a></h2><p>Gunakan S3 channel apabila:</p><ul><li>Anda mahu menyambungkan mana-mana S3-compatible object storage service seperti Cloudflare R2, Backblaze B2, MinIO, AWS S3 atau provider lain yang compatible.</li><li>Anda lebih suka model konfigurasi S3 standard: <code>Endpoint</code>, Access Key dan Secret Key.</li><li>Anda tidak mahu menggunakan native Cloudflare R2 binding channel, atau storage provider anda bukan Cloudflare R2.</li></ul><h2 id="perkara-yang-perlu-disediakan" tabindex="-1">Perkara Yang Perlu Disediakan <a class="header-anchor" href="#perkara-yang-perlu-disediakan" aria-label="Permalink to &quot;Perkara Yang Perlu Disediakan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>S3 API endpoint untuk object storage service.</td></tr><tr><td>Bucket name</td><td>Bucket tempat files disimpan.</td></tr><tr><td>Region</td><td>Storage region. Untuk Cloudflare R2, biasanya <code>auto</code>.</td></tr><tr><td>Access Key ID</td><td>S3 access key ID.</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key.</td></tr><tr><td>CDN domain</td><td>Custom domain pilihan untuk file access.</td></tr></tbody></table><p>Contoh Cloudflare R2 melalui S3 API:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: copied from the Cloudflare R2 API token</span></span>
<span class="line"><span>Secret Access Key: copied from the Cloudflare R2 API token</span></span></code></pre></div><h2 id="di-mana-untuk-menambahnya" tabindex="-1">Di Mana Untuk Menambahnya <a class="header-anchor" href="#di-mana-untuk-menambahnya" aria-label="Permalink to &quot;Di Mana Untuk Menambahnya&quot;">​</a></h2><ol><li>Buka System Settings.</li><li>Pergi ke Upload Settings.</li><li>Klik Add Channel di penjuru kanan atas.</li><li>Pilih <code>S3</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Fungsi</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>Nama mudah dikenali untuk S3 channel, contohnya <code>s3test</code> atau <code>R2-S3</code>.</td><td>Yes</td></tr><tr><td>Enable channel</td><td>Mengawal sama ada channel ini terlibat dalam upload selection.</td><td>Recommended</td></tr><tr><td>Endpoint</td><td>Full S3 service endpoint termasuk <code>https://</code>.</td><td>Yes</td></tr><tr><td>Custom CDN domain</td><td>Optional. Apabila ditetapkan, generated file links akan mengutamakan domain ini.</td><td>No</td></tr><tr><td>Bucket name</td><td>Bucket name, contohnya <code>s3test</code> atau <code>img-r2</code>.</td><td>Yes</td></tr><tr><td>Bucket region</td><td>Region. Untuk Cloudflare R2 biasanya <code>auto</code>.</td><td>Yes</td></tr><tr><td>Access Key ID</td><td>S3 access key ID.</td><td>Yes</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key.</td><td>Yes</td></tr><tr><td>Path-style access</td><td>Compatibility switch. Default off. Sesetengah MinIO, OpenList atau self-hosted S3 services mungkin memerlukannya.</td><td>No</td></tr><tr><td>Quota limit</td><td>Mengawal sama ada S3 channel ini terlibat dalam upload selection berdasarkan capacity.</td><td>No</td></tr><tr><td>Capacity limit</td><td>Required selepas quota limit diaktifkan, contohnya <code>10 GB</code>.</td><td>Required apabila quota limit diaktifkan</td></tr><tr><td>Threshold</td><td>Berhenti menulis apabila usage mencapai percentage ini, contohnya <code>90%</code>.</td><td>Required apabila quota limit diaktifkan</td></tr><tr><td>Remark</td><td>Nota untuk penyelenggaraan sendiri.</td><td>No</td></tr></tbody></table><h2 id="cipta-cloudflare-r2-s3-api-keys" tabindex="-1">Cipta Cloudflare R2 S3 API Keys <a class="header-anchor" href="#cipta-cloudflare-r2-s3-api-keys" aria-label="Permalink to &quot;Cipta Cloudflare R2 S3 API Keys&quot;">​</a></h2><ol><li>Buka Cloudflare Dashboard.</li><li>Pergi ke <code>R2 Object Storage</code>.</li><li>Cari <code>Manage R2 API Tokens</code> atau entry pengurusan API token.</li></ol><p>![R2 API token entry](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>Cipta R2 API token yang boleh mengakses target bucket.</li></ol><p><img src="`+e+'" alt="Create an account API token" loading="lazy"></p><ol start="5"><li>Copy <code>Access Key ID</code> dan <code>Secret Access Key</code> yang dijana.</li></ol><p><img src="'+t+'" alt="Copy the token values" loading="lazy"></p><ol start="6"><li>Kembali ke halaman R2 bucket dan sahkan bucket name.</li><li>Catat S3 API endpoint untuk account. Biasanya kelihatan seperti:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="langkah-setup" tabindex="-1">Langkah Setup <a class="header-anchor" href="#langkah-setup" aria-label="Permalink to &quot;Langkah Setup&quot;">​</a></h2><ol><li>Buka Upload Settings.</li><li>Klik Add Channel.</li><li>Pilih <code>S3</code>.</li><li>Masukkan channel name yang mudah dikenali, contohnya <code>s3test</code>.</li><li>Masukkan S3 API endpoint dalam <code>Endpoint</code>.</li><li>Jika anda menggunakan custom CDN, masukkan dalam <code>Custom CDN domain</code>; jika tidak, biarkan kosong.</li><li>Masukkan bucket name.</li><li>Masukkan region. Untuk contoh Cloudflare R2, gunakan <code>auto</code>.</li><li>Masukkan Access Key ID dan Secret Access Key.</li><li>Biarkan path-style access off kecuali provider menyatakan ia diperlukan.</li><li>Jika mahu capacity control, enable quota limit dan masukkan capacity limit serta threshold.</li><li>Klik Save.</li></ol><p><img src="'+n+'" alt="Add S3 configuration" loading="lazy"></p><h2 id="cara-menyemak" tabindex="-1">Cara Menyemak <a class="header-anchor" href="#cara-menyemak" aria-label="Permalink to &quot;Cara Menyemak&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Cara Menyemak</th></tr></thead><tbody><tr><td>Channel card muncul</td><td>Selepas save, halaman Upload Settings patut memaparkan S3 channel card.</td></tr><tr><td>Channel enabled</td><td>Switch di penjuru kanan atas card patut kekal on.</td></tr><tr><td>Key fields disimpan</td><td>Detail view patut memaparkan Endpoint, Bucket, Region, path-style access dan field berkaitan.</td></tr><tr><td>Upload berfungsi</td><td>Upload test image dan pastikan object muncul dalam target bucket.</td></tr><tr><td>Link dibuka</td><td>Image link yang diberi selepas upload patut dibuka secara normal.</td></tr><tr><td>Capacity display berfungsi</td><td>Jika quota limit diaktifkan, card patut menunjukkan used capacity dan configured limit.</td></tr></tbody></table><p>S3 capacity statistics dikira daripada local file records ImgBed, bukan dengan query provider bucket secara real time. Selepas S3 configuration disimpan, system akan recalculate quota ledger daripada current D1 records.</p><p><img src="'+i+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="patutkah-path-style-access-diaktifkan" tabindex="-1">Patutkah path-style access diaktifkan? <a class="header-anchor" href="#patutkah-path-style-access-diaktifkan" aria-label="Permalink to &quot;Patutkah path-style access diaktifkan?&quot;">​</a></h3><p>Biasanya tidak.</p><p>Aktifkan hanya apabila S3-compatible provider tidak menyokong virtual-hosted-style URLs, atau documentation provider jelas memerlukan path-style access. Sesetengah MinIO, self-hosted S3 dan OpenList-compatible endpoints mungkin memerlukannya.</p><h3 id="cdn-domain-digunakan-untuk-apa" tabindex="-1">CDN domain digunakan untuk apa? <a class="header-anchor" href="#cdn-domain-digunakan-untuk-apa" aria-label="Permalink to &quot;CDN domain digunakan untuk apa?&quot;">​</a></h3><p>Jika anda meletakkan CDN atau custom access domain di hadapan bucket, masukkan di sini.</p><p>Selepas dikonfigurasi, generated file links akan mengutamakan domain ini. Jika tidak menggunakan CDN, biarkan kosong.</p><h3 id="mengapa-upload-gagal" tabindex="-1">Mengapa upload gagal? <a class="header-anchor" href="#mengapa-upload-gagal" aria-label="Permalink to &quot;Mengapa upload gagal?&quot;">​</a></h3><p>Semak perkara ini dahulu:</p><ol><li>Endpoint mengandungi full <code>https://</code> URL.</li><li>Bucket name betul.</li><li>Region sepadan dengan requirement provider.</li><li>Access Key ID dan Secret Access Key disalin lengkap.</li><li>Key mempunyai write permission untuk target bucket.</li><li>Provider tidak memerlukan path-style access, atau path-style access telah diaktifkan jika perlu.</li></ol><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sediakan S3 Endpoint, Bucket, Region, Access Key dan Secret Key</span></span>
<span class="line"><span>-&gt; Buka Upload Settings</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; Pilih S3</span></span>
<span class="line"><span>-&gt; Masukkan Endpoint / Bucket / Region / Access Key / Secret Key</span></span>
<span class="line"><span>-&gt; Masukkan CDN domain jika perlu</span></span>
<span class="line"><span>-&gt; Biarkan path-style access off secara default</span></span>
<span class="line"><span>-&gt; Aktifkan quota limit jika perlu</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; Upload test image dan semak hasilnya</span></span></code></pre></div>`,40)])])}const f=d(r,[["render",c]]);export{y as __pageData,f as default};
